var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"멀린 제사장은 들으시오!","JPN":"マーリン祭祀長、聞いてくれ！","ENG":"Listen here, High Priest Merlin!","TWN":"梅林祭司長，聽著！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"지금 당장 반역자를 넘기지 않으면, 당신부터 그 자리에서 끌어내겠소!","JPN":"今すぐ反逆者を渡さないと、あなたをここから追い出す！","ENG":"If you don't hand over the traitor to us, we will drag you down from your position!","TWN":"如果你現在不交出叛徒，就先把你從那位置上拉下來！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 얘긴 이미 끝났다고 생각했는데.","JPN":"その話はもう終わったと思っていたけど。","ENG":"I believe this conversation was already concluded.","TWN":"我以為那件事已經到此為止了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이를 데려가서 어쩔 셈이지?","JPN":"あの子を連れて行ってどうするつもりかしら。","ENG":"What are you going to do to the child?","TWN":"你打算帶走那個孩子做什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"처단하는 거요! 그루터기와 세계의 안위를 위해서!","JPN":"始末する！　切り株と世界の安危のために！","ENG":"Execute her! This is for the good of the Stump and the world!","TWN":"處決她！為了木墩和世界的安全！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"단 한 명의 희생으로 다른 수많은 목숨을 구한다라…","JPN":"一人の犠牲で他の多くの命を救う、ねえ……","ENG":"Sacrificing one to save the lives of others...","TWN":"用一個人的犧牲來拯救其他無數的生命…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"참 손쉽고 명료해 보이는 해결책이네.","JPN":"とても単純明快な解決策だわ。","ENG":"What a simple and easy resolution you have come up with.","TWN":"真是看起來簡單粗暴的解方呢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 뒤에 있는 사람들도, 모두 그 의견에 찬동해서 온 건가?","JPN":"その後ろにいる人たちも、みんなその意見に同意して来たの？","ENG":"And the people behind you, are they all here in agreement with your views?","TWN":"那些人也都同意這個提議嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"예언은 틀린 적이 없어요! 그 여잘 내버려두면 악마를 끌어들여서 우릴 모두 죽일 거라고요!","JPN":"今まで予言は外れたことがありません！　あの女を放っておけば、悪魔を引き連れみんな殺されてしまう！","ENG":"The prophecies have never been wrong! If we let that girl live, she'll bring in the devil and kill us all!","TWN":"預言哪次出過錯！如果放任那個女孩不管，她會引來魔鬼殺死我們所有人！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그루터기는 예언을 믿고 따르라 가르쳤잖습니까!","JPN":"切り株は予言を信じ、従うよう教えてきたではありませんか！","ENG":"You've taught us to believe and follow the prophecies!","TWN":"木墩教導我們要相信並遵循預言！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"악마와 엮일 게 분명한 인간을 두고만 보다니, 납득할 수 없어요!","JPN":"悪魔と関係のある人間をこのまま見過ごすなんて、納得できません！","ENG":"Yet, I don't understand how you can let this girl who is clearly involved with the devil be here!","TWN":"為什麼你還會允許一個明顯與魔鬼有糾纏的人在這裡？我無法接受！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"우리 목적을 이루려면, 그루터기엔 한 명이라도 더 많은 성자가 필요해.","JPN":"アタシたちの目的を果たすためには、切り株に一人でも多くの聖者が必要だわ。","ENG":"In order to achieve our goal, the Stump needs as many Helgons as we can find.","TWN":"為了實現我們的目標，木墩需要更多的聖者。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"얼마 전 낙원을 관측했으니, 낙원문 기술을 좀 더 발전시키기만 하면 우리 모두가 함께 예견된 종말을 피할 수 있어.","JPN":"この前楽園を観測したから、楽園の門の技術をもう少し発展させればアタシたちみんな予言された終末を回避できるの。","ENG":"Recently, I have observed the Promised Land, and with improvements to our technology, we will be able to avoid the prophesized doom.","TWN":"不久前我們已經觀測到了樂園，只要進一步發展樂園門技術，我們所有人都能一起避開預言中的末日。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러니 조급해말고…","JPN":"だから、焦らずに……","ENG":"So, be patient and–","TWN":"所以不要急…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"낙원문은 아발론의 선조들조차 수백 년간 완성하지 못한 장치지.","JPN":"楽園の門はアバロンの祖先さえ数百年間完成できなかった装置だ。","ENG":"Avalon's Gate is something that not even the ancestors of Avalon could complete.","TWN":"樂園門是阿瓦隆的祖先們幾百年都未能完成的裝置！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"단 한 명의 인간조차 낙원으로 인도하지 못하는 그 커다란 고철덩이는 기약 없는 희망이자 당장의 비참한 현실에서 눈 돌리기 위한 수단일 뿐이오!","JPN":"たった一人の人間すら楽園に導くことのできないあのデカい鉄の塊は、限りない希望であると同時に現在の惨めな現実から目を背けるための手段にすぎない！","ENG":"It has never guided a single person to the Promised Land and is a giant piece of scrap metal using hope as a diversion to get the people's attention away from their miserable reality!","TWN":"那不過是連一個人都無法引導到樂園的巨大廢鐵，一個無望的希望，一個為了逃避眼前悲慘現實而自我欺騙的手段而已！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"何……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그 낙원문에 쓸 적철을 구하기 위해, 제 조부님과 아버지께선 조사단원으로서 목숨을 바치셨어요!","JPN":"その楽園の門に使う赤鉄を探すため、私の祖父と父は調査団員として命を捧げたんです！","ENG":"My father and his father sacrificed their lives as members of the survey corps to find Violarite for Avalon's Gate!","TWN":"為了獲取建造門所需的赤鐵，我的祖父和父親作為調查團員都獻出了生命！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그런데 어째서 한 사람의 목숨에는 그토록 집요하신 겁니까!","JPN":"なのに、どうしてたった一人の命にそこまで固執するのですか！","ENG":"Yet, why are you so obsessed about this one girl's life?!","TWN":"為什麼你要對這個女孩的生命如此執著！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"맞아요! 평생을 그루터기에 숨어 명령만 내려왔으면서 당신만 옳다는 고집은 버리라고요!","JPN":"そうです！　ずっと切り株に隠れて命令していただけのあなたが、正義を主張しないでください！","ENG":"He's right! You've spent your entire life hiding in the Stump and ordering us around! It's time that you learned that your decisions aren't the only ones that are right!","TWN":"沒錯！你一生都只躲在木墩裡發號施令，放棄你那自以為是的固執吧！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희들……","JPN":"アナタたち……","ENG":"You...","TWN":"你們…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그만둬요!","JPN":"やめて！","ENG":"ENOUGH!","TWN":"住手！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"죄도 없는 사람을 몰아가려고 이렇게 많이 모이다니! 다 큰 어른들이 부끄럽지도 않아요?!","JPN":"罪のない人を追いやるためにこんなに大勢集まるなんて！　大人たちが恥ずかしくないんですか！？","ENG":"Aren't you all ashamed of yourselves?! Gathering like this to banish an innocent person?!","TWN":"為了逼迫一個無辜者竟然聚集了這麼多人！你們這些大人不覺得羞恥嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"카롤리스…?","JPN":"カロリス……？","ENG":"Karolis...?","TWN":"卡羅黎斯…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"돌아가. 네가 상관할 일이 아니다.","JPN":"帰れ。お前には関係ない。","ENG":"Go home. This is none of your concern!","TWN":"回去吧，這與你無關。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"상관있어요!","JPN":"関係あります！","ENG":"Of course, it does!","TWN":"有關係！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"루는 마물이 쳐들어왔을 때 우릴 몇 번이고 지켜줬잖아요!","JPN":"ルーは魔物が襲撃してきた時、何度も僕たちを守ってくれたじゃないですか！","ENG":"Lugh has saved our village from the monsters several times!","TWN":"露在怪物入侵時好多次都保護了我們！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"우리가 외지인이라며 의심하고 멀리할 때, 그 사람은 우릴 위해 목숨을 걸고 싸웠다고요!","JPN":"僕たちがよそ者扱いしても、あの人は僕たちのために命をかけて戦ったんです！","ENG":"When we distanced ourselves from her and called her an outsider, she was risking her life to save ours!","TWN":"我們在懷疑她外地人身份的時候，她在為了我們拼命戰鬥！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그런 사람이 세상을 멸망시킬 리가 없잖아요!","JPN":"そんな人が世界を滅亡させるわけがないでしょう！","ENG":"How can you think that a person like that could end the world?!","TWN":"那樣的人怎麼可能毀滅世界啊！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"눈앞의 진실도 바라볼 줄 모르면서…! 그런 어른들이 무슨 예언 타령이에요!","JPN":"目の前の真実でさえちゃんと見ないくせに……！　なにが予言ですか！","ENG":"You are blinded to see the truth that is right in front of your face...! So how can you all go on about some stupid prophecy?!","TWN":"連眼前的真相都看不清…！這樣的人還談什麼看懂預言！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"강한 성자가 약한 우릴 지켜준 것처럼…! 우리도 사람으로서 마땅히 지켜야 하는 게 있는 거잖아요!","JPN":"強い聖者が弱い僕たちを守ってくれたみたいに……！　僕たちも人間として守らなきゃいけないものがあるでしょう！","ENG":"Just like how the strong Helgons protect the weak...! There are things that we should keep as humans!","TWN":"就像強大的聖者保護我們一樣…！我們這些弱者也有應該守護的東西！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"미래를 보장받기 위해 날 지켜준 사람을 해쳐야 한다면…","JPN":"未来を保証するために僕を守ってくれた人に危害を加えろと言うなら……","ENG":"If my future hangs in the balance of having to hurt the people who have protected me so far...","TWN":"如果為了未來必須傷害保護了我的人…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…그렇게 지켜낸 미래따위 난 필요없어요!","JPN":"……そんな未来、僕はいりません！","ENG":"...then I don't need that kind of future!","TWN":"…那樣的未來我不需要！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"우리가 증오하는 악마와 전혀 다를 게 없다고요!","JPN":"僕たちが憎む悪魔と何が違うんですか！","ENG":"That will make us no different from the devils we despise so much!","TWN":"我們和憎恨的魔鬼還有什麼區別！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"하지만 반역자의 죽음으로 종말을 막을 수 있다.","JPN":"だが、反逆者の死で終末を止めることができる。","ENG":"But the end can be prevented with the death of the traitor.","TWN":"但叛徒的死亡可以阻止末日。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"살아가기 위해서라면, 그런 것쯤은 마땅히 포기해야겠지.","JPN":"生き残るためだ。諦めてくれ。","ENG":"Sometimes, you must give up on some things in order to survive.","TWN":"為了生存，這種事情必須被放棄。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"자! 뭣들 하고 있습니까? 어서 반역자를 잡아들입시다!","JPN":"さあ！　何をしている！　早く反逆者を捕まえましょう！","ENG":"Now! It's time! Let's go get that traitor!","TWN":"那麼！你們在幹什麼？快抓住叛徒！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"난 관두겠어.","JPN":"私はやめる。","ENG":"I'm out.","TWN":"我…不幹了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"부끄럽지만… 저 아이 말이 맞아요.","JPN":"恥ずかしいですが……あの子の言うとおりです。","ENG":"I'm ashamed... and the boy is right.","TWN":"雖然很羞愧…但那孩子說得對。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"악마도, 종말도 끔찍하게 두렵지만…","JPN":"悪魔も、終末もすごく恐ろしいですが……","ENG":"Devils and the apocalypse are all terrifying, but...","TWN":"魔鬼也好，末日也好，雖然都很可怕…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"아무 잘못도 없는 사람을 죄인 취급하는 건 나도 싫다고요.","JPN":"何の罪もない人間を罪人扱いするのは、間違っています。","ENG":"I don't want to treat someone who did no wrong as a sinner.","TWN":"把無辜的人當成罪人來對待，我也不喜歡。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"위선적이군.","JPN":"偽善だ。","ENG":"How hypocritical.","TWN":"真是虛偽。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"그 안일한 마음 때문에, 인류가 쌓아온 역사가 내일로 끝난다 해도 말인가?","JPN":"その偽善のせいで、人類が築いてきた歴史が明日で終わるとしても構わないのか？","ENG":"Even if that naive mindset of yours is what will end the vast history of humanity tomorrow?","TWN":"因為那種安逸的心態，就算人類積澱的歷史明天就將被終結也無所謂嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그렇게 된다면, 분명 오늘의 선택을 후회하겠죠.","JPN":"そうなれば、きっと今日の選択を後悔するでしょう。","ENG":"If that is the case, then I'll regret the decision I made today.","TWN":"如果真是那樣，我肯定會後悔今天的選擇吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"그렇다 해도… 악마를 막기 위해 악마가 될 생각은 없습니다.","JPN":"それでも……悪魔を止めるために悪魔になるつもりはありません。","ENG":"But even if so... I will not become a devil to stop one.","TWN":"即便如此…我也不打算為了阻止魔鬼而變成魔鬼。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"시시하군.","JPN":"つまらない。","ENG":"How frivolous.","TWN":"真無聊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"Excuse me...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"참 시시하네요. 몰아치던 격정의 소용돌이가 고작 한 꼬마의 호소 따위에 잠잠해지다니.","JPN":"なんてつまらないのでしょう。高ぶっていた激情の渦が、たった一人のガキの訴えにより鎮まるなんて。","ENG":"It is. This boy's words have calmed the angst within you.","TWN":"真是無聊。洶湧激情的漩渦，竟然因為一個小孩的話而平息。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGITATOR_ROOT_NPC_DEMON","text":{"KOREA":"하지만 상관없습니다.","JPN":"ですが、構いません。","ENG":"But it won't be an issue.","TWN":"但這並不重要。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"뭐, 뭐야? 당신… 왜 얼굴이 일그러지는…?","JPN":"な、何だ？　この人……顔が歪んでる……？","ENG":"W-what? Why... is your face getting all distorted...?","TWN":"什…什麼？你…你…的臉怎麼怪怪的…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신들은 어차피 죽게 될 테니까요.","JPN":"あなたたちはどうせ死ぬことになるでしょうから。","ENG":"Because you are all going to die.","TWN":"反正你們都會死的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"아, 악마…!","JPN":"あ、悪魔……！","ENG":"A-a devil...!","TWN":"啊，魔鬼…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"악마다! 마을에 악마가 나타났어!!!","JPN":"悪魔だ！　村に悪魔が現われた！！！","ENG":"A devil! A devil has appeared in our village!","TWN":"是魔鬼！村子裡出現了魔鬼！！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"풍작의 삼하인.","JPN":"豊作のサウィン。","ENG":"Samhain the Bountiful.","TWN":"是你…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"엘리시온으로 성자들을 보낸 건 역시 당신이었군요, 멀린.","JPN":"エリシオンに聖者たちを送ったのは、やはりあなたでしたか。マーリン。","ENG":"So it was you who sent the Helgons to Elysion, Merlin.","TWN":"把聖者送往艾利森的果然是你，梅林。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네 감옥을 들쑤신 복수라도 하러 온 건가?","JPN":"アナタの牢獄に侵入したことで復讐でもしに来たのかしら。","ENG":"Are you here to take revenge for breaking into your prison?","TWN":"怎麼了，弄壞了你的監獄，所以生氣了嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"저는 명령을 받았을 뿐입니다.","JPN":"私は命令されただけです。","ENG":"I am merely here on orders.","TWN":"我只是接到了命令。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신들이 죽인 제 하수인들의 체취를 쫓아서 말이죠.","JPN":"あなたたちが殺した私の手下たちの匂いを追ってね。","ENG":"Following the scent of my minions that they have killed.","TWN":"追蹤你們殺死的我手下的氣味找到了這裡。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"어쩐지, 구린 냄새가 나더라니.","JPN":"なんだか臭いと思ったわ。","ENG":"Oh, no wonder it smelled awful in here.","TWN":"啊…難怪這裡有股臭味。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이가 갖고 있던 약장을 이용한 거야?","JPN":"あの子が持っていた略章を利用したの？","ENG":"Did you use the badge that she had with her?","TWN":"是利用了那個孩子的藥包嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래요.","JPN":"そのとおり。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"맹세컨대, 이렇게 멀쩡히 군락을 이루고 살아가는 잔존인류가 있는 줄은 마왕도 몰랐을 겁니다.","JPN":"正直、こんなにもちゃんとした集落を作って暮らしている残存人類がいるとは、魔王も知らなかったはずです。","ENG":"I swear, not even the Demon Lord would have known that there were remnants of humanity living in colonies like this.","TWN":"但我發誓，就算連魔王也不曾料到還有你們這樣完好無損的殘存人類。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 말은, 이미 여길 제외한 곳들이 무사하지 않다는 것처럼 들리네.","JPN":"それはつまり、ここ以外のところは無事じゃないって意味に聞こえるわね。","ENG":"Those words make me think that the other places have already been pillaged.","TWN":"這話聽起來，似乎除了這裡，其他地方都不安全了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"전부 사라졌으니까요. 다섯 나라를 역사에서 지우는데 열흘도 채 걸리지 않았습니다.","JPN":"全部消えてしまいましたからね。五つの国を歴史から消すことくらい、十日もかかりませんでしたよ。","ENG":"They are all gone. It did not even take ten days to erase five countries from history.","TWN":"全都消失了，五個國家的歷史還不到十天就都灰飛煙滅了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이번 마왕은… 아주 강하더군요.","JPN":"今度の魔王は……とても強い。","ENG":"This Demon Lord is... extremely strong.","TWN":"這次的魔王…非常強大。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이번 마왕이라고…?","JPN":"今度の魔王……？","ENG":"\\"This\\" Demon Lord..?","TWN":"這次的魔王…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신들을 역병의 간섭으로부터 지켜주는 건, 아마도 저 밑동만 남은 나무겠죠.","JPN":"あなたたちを疫病の干渉から守ってくれているのは、おそらく根本だけが残ったあの木でしょう。","ENG":"The thing that is protecting you all from the plague should be that stump, no?","TWN":"保護你們不受瘟疫干擾的，大概就是那棵只剩下樹根的樹吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"나무를 건들 셈이라면, 네 존재를 걸어야 할 거야.","JPN":"木に手を出すつもりなら、アナタの命をかけるべきよ。","ENG":"If you are thinking of laying your hands on it, you will have to risk your life to do it.","TWN":"如果你打算動那棵樹，就得拿你的命來賭。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후후, 당신이 절 위협할 입장은 아닐 텐데요.","JPN":"ふふ、あなたは私を脅せる立場ではないはずですが。","ENG":"Haha, you are in no position to threaten me.","TWN":"呵呵，你可沒有威脅我的資格。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"마물들이다! 우릴 둘러싸고 있어!","JPN":"魔物だ！　私たちを囲んでる！","ENG":"Monsters! They've surrounded us!","TWN":"是怪物！它們把我們包圍了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"주민들을 선동했던 건, 우릴 모두 한 자리에 모으기 위해서였군.","JPN":"住民を煽ったのは、アタシたちを一カ所に集めるためだったのね。","ENG":"So you instigated all this so you could pen us.","TWN":"煽動居民，是為了把我們全都聚集在一起。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"좀 더 혼란스러운 상황을 원했지만, 그 점은 아쉽게 됐네요.","JPN":"より混乱した状況にしたかったのですが、その点は残念です。","ENG":"I would have preferred a more chaotic scene. How disappointing.","TWN":"本來想要更混亂的局面，但是很遺憾…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린! 내가 도와줄게!","JPN":"マーリン！　あたしが助けてあげる！","ENG":"Merlin! I'll help you!","TWN":"梅林！我來幫你！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"여긴 나한테 맡겨, 귀염둥이.","JPN":"ここはアタシに任せなさい、可愛子ちゃん。","ENG":"Leave this to me, cutie.","TWN":"這裡交給我吧，小可愛。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"대신 그루터기의 주민들을 부탁해.","JPN":"その代わり、切り株の住民を任せたわ。","ENG":"Instead, lead the villagers to safety.","TWN":"你去照顧木墩的居民。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으, 응!","JPN":"う、うん！","ENG":"O-okay!","TWN":"嗯！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후후, 당신 말 한 마디에 저렇게 달아나는 꼴이라니.","JPN":"ふふ、あなたの一言でみんな一目散に逃げ出すとは。","ENG":"Haha, retreating after just a word from you.","TWN":"呵呵，你一句話他們就跑了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"꼭두각시들을 아주 잘 길러내셨군요.","JPN":"とても上手に操り人形を育てたものです。","ENG":"You seem to have trained your puppets well.","TWN":"你真是把這些傀儡訓練得很好啊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이런 건 신뢰가 두텁다고 하는 거야. 호박대가리.","JPN":"これを信頼というのよ。カボチャ頭。","ENG":"This is what we call a strong level of trust, pumpkin head.","TWN":"這叫作信任有加，南瓜頭。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"포위를 당하고도 여유롭네요.","JPN":"囲まれているのに、随分と余裕ですね。","ENG":"Confident, even while you are surrounded.","TWN":"就算是被包圍了嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"과연… 그 여유가 얼마나 가는지 볼까요?","JPN":"はたして……いつまでそうしていられるか、見ものです。","ENG":"Then... let me see how long your confidence will last.","TWN":"那麼…就看看你們的從容能持續多久？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};